// Determine the type of incoming update and extract key data
const input = $input.first().json;
let eventType = 'unknown';
let chatId = '';
let messageText = '';
let callbackData = '';
let callbackQueryId = '';
let userId = '';

if (input.message) {
  chatId = String(input.message.chat.id);
  messageText = input.message.text || '';
  userId = String(input.message.from.id);

  if (messageText.startsWith('/start')) {
    eventType = 'start';
  } else if (messageText.startsWith('/learn')) {
    eventType = 'learn';
  } else if (messageText.startsWith('/quiz')) {
    eventType = 'quiz';
  } else {
    eventType = 'other_message';
  }
} else if (input.callback_query) {
  chatId = String(input.callback_query.message.chat.id);
  callbackData = input.callback_query.data || '';
  callbackQueryId = input.callback_query.id;
  userId = String(input.callback_query.from.id);
  messageText = callbackData;

  if (callbackData.startsWith('select_material_')) {
    eventType = 'select_material';
  } else if (callbackData.startsWith('answer_') || callbackData.startsWith('ans_')) {
    eventType = 'quiz_answer';
  } else if (callbackData === 'start_quiz') {
    eventType = 'quiz';
  } else {
    eventType = 'other_callback';
  }
}

return [{
  json: {
    eventType,
    chatId,
    messageText,
    callbackData,
    callbackQueryId,
    userId
  }
}];

// Extract URL from /learn command
const text = $('Parse Input').item.json.messageText;
const chatId = $('Parse Input').item.json.chatId;
const userId = $('Parse Input').item.json.userId;

// Find URL in the message
const urlMatch = text.match(/https?:\/\/[^\s]+/);

if (!urlMatch) {
  return [{
    json: {
      error: true,
      chatId,
      userId,
      errorMessage: '⚠️ Please provide a URL after the /learn command.\n\nExample: /learn https://example.com/article'
    }
  }];
}

return [{
  json: {
    error: false,
    url: urlMatch[0],
    chatId,
    userId
  }
}];

// Clean HTML and extract text content
const html = $input.first().json.data || $input.first().json.body || '';
const url = $('Extract URL').item.json.url;
const chatId = $('Extract URL').item.json.chatId;
const userId = $('Extract URL').item.json.userId;

if (!html || html.length < 50) {
  return [{
    json: {
      error: true,
      chatId,
      userId,
      url,
      content: '',
      errorMessage: '⚠️ Could not fetch content from this URL. Please check the link and try again.'
    }
  }];
}

// Remove script, style, nav, footer, header tags and their content
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\s+/g, ' ')
  .trim();

// Limit to ~4000 chars for AI processing
if (text.length > 4000) {
  text = text.substring(0, 4000) + '...';
}

// Extract title from HTML
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
const h1Match = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
const rawTitle = titleMatch ? titleMatch[1].trim() : (h1Match ? h1Match[1].trim() : url);

return [{
  json: {
    error: false,
    content: text,
    rawTitle,
    url,
    chatId,
    userId
  }
}];

// Parse the Teacher AI response and format for storage and display
const aiOutput = $input.first().json.output || $input.first().json.text || '';
const chatId = $('Clean HTML').item.json.chatId;
const userId = $('Clean HTML').item.json.userId;
const url = $('Clean HTML').item.json.url;
const content = $('Clean HTML').item.json.content;

let parsed;
try {
  // Try to extract JSON from the response
  let jsonStr = aiOutput;
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonStr = jsonMatch[0];
  parsed = JSON.parse(jsonStr);
} catch(e) {
  // Fallback if AI didn't return valid JSON
  parsed = {
    title: $('Clean HTML').item.json.rawTitle || 'Untitled Material',
    difficulty: 'intermediate',
    mainConcepts: ['See summary'],
    keyPoints: ['Content was analyzed but structured extraction failed. Please try again.'],
    summary: aiOutput.substring(0, 300)
  };
}

// Generate material ID
const materialId = 'LM-' + Date.now();
const addedDate = new Date().toISOString();

// Format message for Telegram
const difficultyEmoji = {
  'beginner': '🟢 Beginner',
  'intermediate': '🟡 Intermediate',
  'advanced': '🔴 Advanced'
};

const keyPointsList = (parsed.keyPoints || []).map((p, i) => `${i+1}. ${p}`).join('\n');
const conceptsList = (parsed.mainConcepts || []).join(', ');

const telegramMessage = `📚 *${parsed.title || 'Learning Material'}*\n\n` +
  `📊 Difficulty: ${difficultyEmoji[parsed.difficulty] || parsed.difficulty}\n\n` +
  `💡 *Main Concepts:* ${conceptsList}\n\n` +
  `📝 *Key Points:*\n${keyPointsList}\n\n` +
  `📖 *Summary:* ${parsed.summary || 'N/A'}\n\n` +
  `🔗 Source: ${url}`;

return [{
  json: {
    materialId,
    url,
    title: parsed.title || 'Untitled',
    content,
    addedDate,
    difficulty: parsed.difficulty || 'intermediate',
    summary: parsed.summary || '',
    keyPoints: JSON.stringify(parsed.keyPoints || []),
    mainConcepts: JSON.stringify(parsed.mainConcepts || []),
    chatId,
    userId,
    telegramMessage
  }
}];

