// Parse quiz questions and save to Google Sheets, then send first question
const aiOutput = $input.first().json.output || $input.first().json.text || '';
const chatId = $('Find Selected Material').item.json.chatId;
const userId = $('Find Selected Material').item.json.userId;
const materialId = $('Find Selected Material').item.json.materialId;
const title = $('Find Selected Material').item.json.title;

let parsed;
try {
  let jsonStr = aiOutput;
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonStr = jsonMatch[0];
  parsed = JSON.parse(jsonStr);
} catch(e) {
  return [{
    json: {
      error: true,
      chatId,
      userId,
      message: '⚠️ Failed to generate quiz. Please try again with /quiz.'
    }
  }];
}

const questions = parsed.questions || [];
if (questions.length === 0) {
  return [{
    json: {
      error: true,
      chatId,
      userId,
      message: '⚠️ No questions generated. Please try again.'
    }
  }];
}

// Create a quiz session ID
const quizSessionId = 'QS-' + Date.now();

// Build all quiz data for storage
const quizData = {
  quizSessionId,
  materialId,
  title,
  chatId,
  userId,
  questions: JSON.stringify(questions),
  currentQuestion: 0,
  answers: JSON.stringify([]),
  startedAt: new Date().toISOString(),
  status: 'active'
};

// Build first question message
const q = questions[0];
const questionText = `📝 *Quiz: ${title}*\n\n` +
  `*Question 1 of ${questions.length}:*\n` +
  `${q.question}\n\n` +
  `A) ${q.options.A}\n` +
  `B) ${q.options.B}\n` +
  `C) ${q.options.C}\n` +
  `D) ${q.options.D}`;

const keyboard = {
  inline_keyboard: [
    [
      { text: 'A', callback_data: `answer_${quizSessionId}_0_A` },
      { text: 'B', callback_data: `answer_${quizSessionId}_0_B` },
      { text: 'C', callback_data: `answer_${quizSessionId}_0_C` },
      { text: 'D', callback_data: `answer_${quizSessionId}_0_D` }
    ]
  ]
};

return [{
  json: {
    ...quizData,
    error: false,
    firstQuestionText: questionText,
    firstQuestionKeyboard: JSON.stringify(keyboard)
  }
}];

