// Extract answer data from callback
const callbackData = $('Parse Input').item.json.callbackData;
const chatId = $('Parse Input').item.json.chatId;
const userId = $('Parse Input').item.json.userId;
const callbackQueryId = $('Parse Input').item.json.callbackQueryId;

// Two formats:
// First question: answer_SESSIONID_0_LETTER (no history)
// Later questions: ans_SESSIONID_INDEX_LETTER_HISTORY (with history like A,B,C)

let quizSessionId, questionIndex, answerLetter, previousAnswers;

if (callbackData.startsWith('ans_')) {
  // New format with history: ans_SESSION_INDEX_LETTER_HISTORY
  const withoutPrefix = callbackData.substring(4); // remove 'ans_'
  const lastUnderscore4 = withoutPrefix.lastIndexOf('_'); // before HISTORY
  const historyPart = withoutPrefix.substring(lastUnderscore4 + 1); // e.g. "A,B,C"
  const rest = withoutPrefix.substring(0, lastUnderscore4); // SESSION_INDEX_LETTER

  const lastUnderscore3 = rest.lastIndexOf('_'); // before LETTER
  answerLetter = rest.substring(lastUnderscore3 + 1);
  const rest2 = rest.substring(0, lastUnderscore3); // SESSION_INDEX

  const lastUnderscore2 = rest2.lastIndexOf('_'); // before INDEX
  questionIndex = parseInt(rest2.substring(lastUnderscore2 + 1));
  quizSessionId = rest2.substring(0, lastUnderscore2);

  previousAnswers = historyPart;
} else {
  // Original format: answer_SESSIONID_INDEX_LETTER
  const parts = callbackData.split('_');
  // parts[0] = 'answer', rest needs to be parsed carefully
  // Session ID might contain underscores, so we parse from the end
  answerLetter = parts[parts.length - 1];
  questionIndex = parseInt(parts[parts.length - 2]);
  quizSessionId = parts.slice(1, parts.length - 2).join('_');
  previousAnswers = '';
}

return [{
  json: {
    quizSessionId,
    questionIndex,
    answerLetter,
    previousAnswers,
    chatId,
    userId,
    callbackQueryId
  }
}];

// Process the answer and determine next action
const items = $input.all();
const quizSessionId = $('Extract Answer').item.json.quizSessionId;
const questionIndex = $('Extract Answer').item.json.questionIndex;
const answerLetter = $('Extract Answer').item.json.answerLetter;
const chatId = $('Extract Answer').item.json.chatId;
const userId = $('Extract Answer').item.json.userId;

// Find the active quiz session
const session = items.find(item => item.json.quizSessionId === quizSessionId);

if (!session) {
  return [{
    json: {
      action: 'error',
      chatId,
      message: '⚠️ Quiz session not found. Start a new quiz with /quiz.'
    }
  }];
}

const questions = JSON.parse(session.json.questions);

// Get previous answers from Extract Answer node (passed via callback_data)
const previousAnswersStr = $('Extract Answer').item.json.previousAnswers || '';

// Rebuild full answer history
// previousAnswersStr is like "A,B,C,D" — one letter per answered question
let previousLetters = previousAnswersStr ? previousAnswersStr.split(',') : [];

// Build full answers array from history
let answers = [];
for (let i = 0; i < previousLetters.length; i++) {
  const q = questions[i];
  if (q) {
    answers.push({
      questionIndex: i,
      questionId: q.id,
      userAnswer: previousLetters[i],
      correctAnswer: q.correctAnswer,
      isCorrect: previousLetters[i] === q.correctAnswer,
      question: q.question,
      explanation: q.explanation
    });
  }
}

// Add current answer
const currentQ = questions[questionIndex];
const isCorrect = answerLetter === currentQ.correctAnswer;
answers.push({
  questionIndex,
  questionId: currentQ.id,
  userAnswer: answerLetter,
  correctAnswer: currentQ.correctAnswer,
  isCorrect,
  question: currentQ.question,
  explanation: currentQ.explanation
});

// Build the string of all answers so far (to pass forward)
const allAnswersStr = answers.map(a => a.userAnswer).join(',');

const nextIndex = questionIndex + 1;
const isLastQuestion = nextIndex >= questions.length;

// Feedback for current answer
const feedback = isCorrect 
  ? '✅ Correct!' 
  : `❌ Wrong. Correct: ${currentQ.correctAnswer}\n💡 ${currentQ.explanation}`;

if (isLastQuestion) {
  const correctCount = answers.filter(a => a.isCorrect).length;
  const totalQuestions = questions.length;
  const scorePercent = Math.round((correctCount / totalQuestions) * 100);

  let resultEmoji = '🎉';
  if (scorePercent < 40) resultEmoji = '📚';
  else if (scorePercent < 70) resultEmoji = '💪';

  let resultsText = `${resultEmoji} Quiz Results: ${session.json.title}\n\n`;
  resultsText += `Score: ${correctCount}/${totalQuestions} (${scorePercent}%)\n\n`;

  answers.forEach((a, i) => {
    const icon = a.isCorrect ? '✅' : '❌';
    resultsText += `${icon} Q${i+1}: ${a.question}\n`;
    resultsText += `Your answer: ${a.userAnswer} | Correct: ${a.correctAnswer}\n`;
    if (!a.isCorrect) {
      resultsText += `💡 ${a.explanation}\n`;
    }
    resultsText += '\n';
  });

  if (scorePercent === 100) resultsText += '🏆 Perfect score! Excellent work!';
  else if (scorePercent >= 70) resultsText += '👏 Great job! You know this material well.';
  else if (scorePercent >= 40) resultsText += '📖 Good effort! Review the material and try again.';
  else resultsText += '📚 Keep studying! Use /learn to review the material.';

  return [{
    json: {
      action: 'show_results',
      chatId,
      userId,
      quizSessionId,
      answers: JSON.stringify(answers),
      feedback,
      resultsText,
      scorePercent,
      status: 'completed'
    }
  }];
} else {
  const nextQ = questions[nextIndex];
  const questionText = `📝 Question ${nextIndex + 1} of ${questions.length}:\n` +
    `${nextQ.question}\n\n` +
    `A) ${nextQ.options.A}\n` +
    `B) ${nextQ.options.B}\n` +
    `C) ${nextQ.options.C}\n` +
    `D) ${nextQ.options.D}`;

  // Pass answer history in callback_data: answer_SESSION_INDEX_LETTER_HISTORY
  const keyboard = {
    inline_keyboard: [
      [
        { text: 'A', callback_data: `ans_${quizSessionId}_${nextIndex}_A_${allAnswersStr}` },
        { text: 'B', callback_data: `ans_${quizSessionId}_${nextIndex}_B_${allAnswersStr}` },
        { text: 'C', callback_data: `ans_${quizSessionId}_${nextIndex}_C_${allAnswersStr}` },
        { text: 'D', callback_data: `ans_${quizSessionId}_${nextIndex}_D_${allAnswersStr}` }
      ]
    ]
  };

  return [{
    json: {
      action: 'next_question',
      chatId,
      userId,
      quizSessionId,
      answers: JSON.stringify(answers),
      currentQuestion: nextIndex,
      feedback,
      nextQuestionText: questionText,
      nextQuestionKeyboard: JSON.stringify(keyboard),
      status: 'active'
    }
  }];
}
